    req_id = "_" + str(uuid.uuid4())
    session["authn_request_id"] = req_id

    sp_entityid = _get_env("SP_ENTITY_ID", _url_for("/metadata"))
    acs_url = _get_env("SP_ACS_URL", _url_for("/acs"))
