@app.route("/acs", methods=["POST"])
def acs():
    saml_response_b64 = request.form.get("SAMLResponse")
    relay_state = request.form.get("RelayState") or session.get("relay_state") or _get_env("DEFAULT_RELAY_STATE", _url_for("/me"))
    if not saml_response_b64:
        return make_response("Missing SAMLResponse", 400)

    mode = _get_mode()

    if mode == "python3-saml":
        _require_python3_saml()
        auth = OneLogin_Saml2_Auth(prepare_flask_request(request), build_sp_settings())
        request_id = session.get("authn_request_id")
        auth.process_response(request_id=request_id)
        errors = auth.get_errors()
        if errors:
            logger.warning("SAML errors: %s reason=%s", errors, auth.get_last_error_reason())
            return make_response("SAML validation failed: " + "; ".join(errors), 401)

        if not auth.is_authenticated():
            return make_response("Not authenticated", 401)

        name_id = auth.get_nameid()
        attrs = auth.get_attributes() or {}
        session_index = auth.get_session_index()
        assertion_id = auth.get_last_assertion_id()

        user = {
            "user_id": (attrs.get("email", [None])[0] if isinstance(attrs.get("email"), list) else attrs.get("email")) or name_id,
            "name_id": name_id,
            "attributes": attrs,
            "issuer": auth.get_issuer(),
            "session_index": session_index,
            "assertion_id": assertion_id,
        }
        session["user"] = user
        session["saml"] = {
            "name_id": name_id,
            "session_index": session_index,
            "assertion_id": assertion_id,
        }
        return redirect(relay_state)

    # lxml-only mode: parse, require a ds:Signature element exists, extract assertion data, then "authenticate"
    try:
        xml_bytes = _b64decode(saml_response_b64)
    except Exception:
        return make_response("Invalid base64 SAMLResponse", 400)

    if not lxml_validate_signature_exists(xml_bytes):
        return make_response("SAMLResponse missing XML Signature", 401)

    info = lxml_extract_assertion_info(xml_bytes)

    status = info.get("status")
    if status and status != "urn:oasis:names:tc:SAML:2.0:status:Success":
        return make_response("SAML status not success: " + str(status), 401)

    expected_aud = _get_env("SP_ENTITY_ID", _url_for("/metadata"))
    auds = info.get("audiences") or []
    if auds and expected_aud not in auds:
        return make_response("Audience mismatch", 401)

    user = authenticate_user_from_saml(info)
    if not user:
        return make_response("Unable to map SAML assertion to a user", 401)

    session["user"] = user
    session["saml"] = {
        "name_id": info.get("name_id"),
        "session_index": info.get("session_index"),
        "assertion_ids": info.get("assertion_ids"),
    }
    return redirect(relay_state)


